svg.script:
(async function() {
const status = document.getElementById('status');
const wrapper = document.getElementById('wrapper');
const frame = document.getElementById('app-frame');
const url = 'https://cdn.jsdelivr.net/gh/fidgetsetc/birdmath@main/singlefile.html';
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(&#39;Network error&#39;);
    const code = await response.text();

    // Create the blob portal
    const blob = new Blob([code], { type: &#39;text/html&#39; });
    const blobUrl = URL.createObjectURL(blob);

    frame.onload = () =&gt; {
      status.setAttribute(&#39;visibility&#39;, &#39;hidden&#39;);
      wrapper.setAttribute(&#39;visibility&#39;, &#39;visible&#39;);
    };

    frame.src = blobUrl;
  } catch (e) {
    status.textContent = &quot;ERROR: &quot; + e.message;
    status.setAttribute(&#39;fill&#39;, &#39;#ff0000&#39;);
  }
})();
]]&gt;
</script>
</svg>
